import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("Quote — base premiums", () => {
    it.todo("returns 5 G for an empty item list (processing fee only)");
    it.todo("returns base premium + fee for a single sword (100 + 5 = 105 G)");
    it.todo("returns base premium + fee for a single amulet (60 + 5 = 65 G)");
    it.todo("returns base premium + fee for a single staff (80 + 5 = 85 G)");
    it.todo("returns base premium + fee for a single potion (40 + 5 = 45 G)");
    it.todo("returns 25 G base premium per component (e.g. 2 runes → 50 + 5 = 55 G)");
    it.todo("applies block discount for exactly 3 alike components (3 runes → 60 + 5 = 65 G)");
    it.todo("does not apply block for 4 alike components (4 runes → 100 + 5 = 105 G)");
    it.todo("applies separate blocks for different component types (3 runes + 3 moonstones → 120 + 5 = 125 G)");
    it.todo("does not apply block for mixed component types (2 runes + 1 moonstone → 75 + 5 = 80 G)");
    it.todo("sums base premiums for multiple main items (sword + amulet → 160 + 5 = 165 G)");
  });

  describe("Quote — item-specific modifiers", () => {
    it.todo("adds 50% cursed surcharge to the cursed item's base premium only");
    it.todo("adds 30% high-enchantment surcharge for enchantment >= 5");
    it.todo("does not add high-enchantment surcharge for enchantment 4");
    it.todo("applies both cursed and high-enchantment surcharges to the same item");
    it.todo("applies cursed surcharge only to cursed item in a multi-item policy");
  });

  describe("Quote — policy-wide modifiers", () => {
    it.todo("applies 10% first-insurance surcharge for a newcomer");
    it.todo("applies 20% loyalty discount for customer with >= 2 years");
    it.todo("applies 15% follow-up contract discount on second quote");
    it.todo("applies loyalty, first-insurance, and follow-up together for long-standing repeat customer");
  });

  describe("Quote — rounding", () => {
    it.todo("rounds premium up (in MHPCO's favor) on the final result");
  });

  describe("Quote — integration", () => {
    it.todo("newcomer with cursed sword yields 165 G");
    it.todo("long-standing customer second contract with cursed high-enchant sword yields 160 G");
  });

  describe("Claim — standard reimbursement", () => {
    it.todo("reimburses damage minus 100 G deductible for a regular item");
    it.todo("reimburses component damage minus 100 G deductible");
    it.todo("applies deductible per damaged item in a multi-damage event");
  });

  describe("Claim — enchantment and material clauses", () => {
    it.todo("reimburses 50% for enchantment >= 8, then deductible");
    it.todo("fully reimburses dragon material items, then deductible");
    it.todo("applies 50% when both dragon material and enchantment >= 8");
    it.todo("fully reimburses dragon material with enchantment < 8, then deductible");
  });

  describe("Claim — cap", () => {
    it.todo("caps total payout at 2x insurance sum of the policy");
    it.todo("tracks remaining cap across multiple claims on same policy");
  });

  describe("Claim — payout rounding", () => {
    it.todo("rounds payout down (in MHPCO's favor) on the final result");
  });

  describe("Error handling", () => {
    it.todo("rejects unknown item type in a quote");
    it.todo("rejects claim referencing an item not in the policy");
    it.todo("rejects negative damage amount");
    it.todo("rejects more damages of a type than the policy covers");
  });
});

