interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

interface Step {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

interface QuoteResult {
  premium: number;
}

interface ScenarioOutput {
  results: QuoteResult[];
}

const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
};

export function processScenario(scenario: Scenario): ScenarioOutput {
  const results = scenario.steps.map((step) => {
    let basePremium = 0;
    for (const item of step.items) {
      basePremium += BASE_PREMIUMS[item.type] ?? 0;
    }
    const premium = basePremium + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

