toolUseResult.originalFile:
interface Item {
  type: string;
  material: string;
  enchantment: number;
  cursed: boolean;
}

interface Step {
  op: "quote";
  items: Item[];
}

interface Scenario {
  customer: { yearsWithMHPCO: number };
  steps: Step[];
}

interface QuoteResult {
  premium: number;
}

interface ScenarioOutput {
  results: QuoteResult[];
}

const PROCESSING_FEE = 5;
const CURSED_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const LOYALTY_DISCOUNT_RATE = 0.2;
const LOYALTY_THRESHOLD_YEARS = 2;
const FOLLOW_UP_DISCOUNT_RATE = 0.15;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
  moonstone: 25,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
const BLOCK_SIZE = 3;
const BLOCK_PREMIUM = 60;

const calculateComponentPremium = (type: string, count: number): number =>
  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);

const calculateItemPremium = (item: Item): number => {
  const base = BASE_PREMIUMS[item.type] ?? 0;
  const cursedSurcharge = item.cursed ? base * CURSED_SURCHARGE_RATE : 0;
  const enchantmentSurcharge =
    item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD
      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
      : 0;
  return base + cursedSurcharge + enchantmentSurcharge;
};

const calculatePremiums = (items: Item[]): { rawBase: number; totalWithSurcharges: number } => {
  const componentCounts = new Map<string, number>();
  let rawBase = 0;
  let totalWithSurcharges = 0;

  for (const item of items) {
    if (COMPONENT_TYPES.has(item.type)) {
      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
    } else {
      rawBase += BASE_PREMIUMS[item.type] ?? 0;
      totalWithSurcharges += calculateItemPremium(item);
    }
  }

  for (const [type, count] of componentCounts) {
    const componentPremium = calculateComponentPremium(type, count);
    rawBase += componentPremium;
    totalWithSurcharges += componentPremium;
  }

  return { rawBase, totalWithSurcharges };
};

export function processScenario(scenario: Scenario): ScenarioOutput {
  const results = scenario.steps.map((step, index) => {
    const basePremium = calculateBasePremium(step.items);
    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
    const followUpDiscount = index > 0 ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
    const policyPremium = basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE - loyaltyDiscount - followUpDiscount;
    const premium = Math.ceil(policyPremium) + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

