export function processScenario(scenario: Scenario): ScenarioOutput {
  const policies: { items: Item[] }[] = [];
  const capRemaining = new Map<number, number>();

  const results = scenario.steps.map((step, index) => {
    if (step.op === "quote") {
      policies.push({ items: step.items });
      const { basePremiumTotal, totalWithSurcharges } = calculatePremiums(step.items);
      const policyModifier = calculatePolicyModifier(basePremiumTotal, scenario.customer.yearsWithMHPCO, index > 0);
      const premium = Math.ceil(totalWithSurcharges + policyModifier) + PROCESSING_FEE;

      const insuranceSum = step.items.reduce((sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0), 0);
      capRemaining.set(policies.length - 1, insuranceSum * 2);

      return { premium };
    } else {
      const policyIndex = step.policy;
      let totalPayout = 0;

      for (const damage of step.incident.damages) {
        const reimbursement = damage.amount - DEDUCTIBLE;
        totalPayout += Math.max(0, reimbursement);
      }

      const cap = capRemaining.get(policyIndex) ?? 0;
      const payout = Math.min(totalPayout, cap);
      const remaining = cap - payout;
      capRemaining.set(policyIndex, remaining);

      return { payout, remainingCap: remaining };
    }
  });
  return { results };
}

